// Tokens de cor das variações (alinhados ao DSS)
const VARIANTS = {
  default: {
    agencyColor: "#a4a6a5",
    sansysColor: "#a4a6a5",
    accent: "#a4a6a5",
  },
  colored: {
    agencyColor: "#1ba39c",
    sansysColor: "#1d4971",
    accent: "#1ba39c",
  },
} as const;

export type LogoVariant = keyof typeof VARIANTS;

export interface SansysAgencyLogoProps {
  className?: string;
  /** Preset de cores. 'default' = monocromático neutro, 'colored' = cores da marca. */
  variant?: LogoVariant;
  /**
   * Cor do wordmark "Agency".
   * Sobrepõe a cor definida pelo variant.
   */
  agencyColor?: string;
  /**
   * Cor do wordmark "Sansys".
   * Sobrepõe a cor definida pelo variant.
   */
  sansysColor?: string;
  /** Cor do shape 1 do ícone (shape frontal, opacity 0.5). Sobrepõe o variant. */
  accentColor1?: string;
  /** Cor do shape 2 do ícone (shape central, opacity 0.6). Sobrepõe o variant. */
  accentColor2?: string;
  /** Cor do shape 3 do ícone (shape traseiro, opacity 0.7). Sobrepõe o variant. */
  accentColor3?: string;
  /**
   * @deprecated Use `agencyColor` + `sansysColor` para controle granular,
   * ou `variant` para presets. Mantido por compatibilidade.
   */
  color?: string;
}

export function SansysAgencyLogo({
  className = "h-12",
  variant = "default",
  agencyColor,
  sansysColor,
  accentColor1,
  accentColor2,
  accentColor3,
  color, // legacy
}: SansysAgencyLogoProps) {
  const base = VARIANTS[variant];

  // Resolução de cor: prop explícita > legacy `color` > valor do variant
  const resolvedAgency  = agencyColor  ?? color ?? base.agencyColor;
  const resolvedSansys  = sansysColor  ?? color ?? base.sansysColor;
  const resolvedAccent1 = accentColor1 ?? color ?? base.accent;
  const resolvedAccent2 = accentColor2 ?? color ?? base.accent;
  const resolvedAccent3 = accentColor3 ?? color ?? base.accent;

  return (
    <svg
      className={className}
      viewBox="0 0 149 42"
      xmlns="http://www.w3.org/2000/svg"
      aria-label="Sansys Agency"
      role="img"
    >
      <g>
        {/* Wordmark: Agency */}
        <path fill={resolvedAgency} d={AGENCY_PATH} />

        {/* Wordmark: Sansys */}
        <path fill={resolvedSansys} d={SANSYS_PATH} />

        {/* Ícone geométrico: três shapes sobrepostos */}
        <g>
          <path
            fill={resolvedAccent2}
            opacity="0.6"
            d="M4.7,14.9L1,36.1c0,.6.3,1.1.9,1.1h25.2c.4,0,.8-.3.9-.7l3.7-21.2c0-.6-.3-1.1-.9-1.1H5.6c-.4,0-.8.3-.9.7Z"
          />
          <path
            fill={resolvedAccent3}
            opacity="0.7"
            d="M27.5,6l-6,33.9c0,.6.3,1.1.9,1.1h9.8c.4,0,.8-.3.9-.7l6-33.9c0-.6-.3-1.1-.9-1.1h-9.8c-.4,0-.8.3-.9.7Z"
          />
          <path
            fill={resolvedAccent1}
            opacity="0.5"
            d="M10.9,1.7l-1.4,7.9c0,.6.3,1.1.9,1.1h21.4c.4,0,.8-.3.9-.7l1.4-7.9c0-.6-.3-1.1-.9-1.1H11.8c-.4,0-.8.3-.9.7Z"
          />
        </g>
      </g>
    </svg>
  );
}